SELECT COUNT(*) AS total_records 
FROM blood_type_distribution 
WHERE year = 2023;

SELECT country_id, o_pos, year
FROM blood_type_distribution
WHERE year = 2023;

SELECT center_name, capacity 
FROM donation_centers 
WHERE country_id = 1;

SELECT SUM(total_units) AS total_O_pos_units
FROM blood_bank_inventory
WHERE blood_group = 'O' AND rhesus_factor = 'Positive';

SELECT COUNT(*) 
FROM blood_donation_records 
WHERE blood_type_id = 1;

SELECT COUNT(*) AS prevalence_count
FROM blood_type_prevalence
WHERE year = 2023;

SELECT blood_group, total_units 
FROM blood_bank_inventory 
WHERE center_id = 1;

SELECT DISTINCT gender
FROM donors
WHERE data_version = 1;
